#include <stdio.h>
#include <stdlib.h>
struct Entry {
    int val; int idx;
};
int cmp(const void* a, const void* b) {
    return ((struct Entry*)a)->val - ((struct Entry*)b)->val;
}
int main() {
    int n, target;
    if (scanf("%d %d", &n, &target) == 2) {
        struct Entry* arr = malloc(n * sizeof(struct Entry));
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i].val);
            arr[i].idx = i;
        }
        qsort(arr, n, sizeof(struct Entry), cmp);
        int l = 0, r = n - 1;
        while (l < r) {
            int sum = arr[l].val + arr[r].val;
            if (sum == target) {
                int i1 = arr[l].idx, i2 = arr[r].idx;
                if (i1 > i2) { int t = i1; i1 = i2; i2 = t; }
                printf("%d %d\n", i1, i2);
                break;
            } else if (sum < target) l++;
            else r--;
        }
        free(arr);
    }
    return 0;
}

