#include <iostream>
#include <string>
#include <stack>
using namespace std;
int main() {
    string s; cin >> s;
    stack<char> st;
    bool ok = true;
    for(char c : s) {
        if (c == '(' || c == '{' || c == '[') st.push(c);
        else {
            if (st.empty()) { ok = false; break; }
            if (c == ')' && st.top() != '(') { ok = false; break; }
            if (c == '}' && st.top() != '{') { ok = false; break; }
            if (c == ']' && st.top() != '[') { ok = false; break; }
            st.pop();
        }
    }
    if(!st.empty()) ok = false;
    cout << (ok ? "YES" : "NO") << endl;
    return 0;
}

