#include <stdio.h>
#include <stdlib.h>
void dfs(char** grid, int r, int c, int rows, int cols) {
    if (r < 0 || r >= rows || c < 0 || c >= cols || grid[r][c] == '0') return;
    grid[r][c] = '0';
    dfs(grid, r+1, c, rows, cols);
    dfs(grid, r-1, c, rows, cols);
    dfs(grid, r, c+1, rows, cols);
    dfs(grid, r, c-1, rows, cols);
}
int main() {
    int r, c;
    if (scanf("%d %d", &r, &c) == 2) {
        char** grid = malloc(r * sizeof(char*));
        for (int i = 0; i < r; i++) {
            grid[i] = malloc(c * sizeof(char));
            for (int j = 0; j < c; j++) {
                char buf[10]; scanf("%s", buf);
                grid[i][j] = buf[0];
            }
        }
        int count = 0;
        for (int i = 0; i < r; i++) {
            for (int j = 0; j < c; j++) {
                if (grid[i][j] == '1') {
                    count++;
                    dfs(grid, i, j, r, c);
                }
            }
        }
        printf("%d\n", count);
        for(int i = 0; i < r; i++) free(grid[i]);
        free(grid);
    }
    return 0;
}

