    int n; cin >> n;
    vector<int> p(n);
    for(int i=0; i<n; i++) cin >> p[i];
    vector<int> d(n, 0);
    int ans = 0;
    for(int i=0; i<n; i++) ans = max(ans, get_depth(i, p, d));
    cout << ans << endl;
    return 0;
}

