#include <algorithm>
using namespace std;
int dfs(vector<vector<char>>& grid, int r, int c, int rows, int cols) {
    if (r < 0 || r >= rows || c < 0 || c >= cols || grid[r][c] == '0') return 0;
    grid[r][c] = '0';
    return 1 + dfs(grid, r+1, c, rows, cols) +
               dfs(grid, r-1, c, rows, cols) +
               dfs(grid, r, c+1, rows, cols) +
               dfs(grid, r, c-1, rows, cols);
}
