    vector<vector<char>> grid(rows, vector<char>(cols));
    for (int i = 0; i < rows; i++)
        for (int j = 0; j < cols; j++) cin >> grid[i][j];
    int ans = 0;
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            if (grid[i][j] == '1') {
                ans = max(ans, dfs(grid, i, j, rows, cols));
            }
        }
    }
    cout << ans << endl;
    return 0;
}

