    int n, target;
    if (scanf("%d %d", &n, &target) == 2) {
        int* coins = malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) scanf("%d", &coins[i]);
        int* dp = malloc((target + 1) * sizeof(int));
        dp[0] = 0;
        for (int i = 1; i <= target; i++) dp[i] = 1e9;
        for (int j = 0; j < n; j++) {
            int c = coins[j];
            for (int i = c; i <= target; i++) {
                dp[i] = min(dp[i], dp[i - c] + 1);
            }
        }
        printf("%d\n", dp[target] >= 1e9 ? -1 : dp[target]);
        free(coins); free(dp);
    }
    return 0;
}

