#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
using namespace std;
int main(){
    string w1,w2; cin>>w1>>w2;
    int m=w1.size(),n=w2.size();
    vector<int> dp(n+1);
    for(int j=0;j<=n;j++) dp[j]=j;
    for(int i=1;i<=m;i++){
        int prev=dp[0]; dp[0]=i;
        for(int j=1;j<=n;j++){
            int tmp=dp[j];
            if(w1[i-1]==w2[j-1]) dp[j]=prev;
            else dp[j]=1+min({prev,dp[j-1],dp[j]});
            prev=tmp;
        }
    }
    cout<<dp[n]<<endl;
    return 0;
}

